-- E-commerce Database Schema with 10 Tables and Sample Data
CREATE DATABASE ecommerce_db;

-- 1. Currencies table
CREATE TABLE currencies (
    currency_id SERIAL PRIMARY KEY,
    currency_code VARCHAR(3) NOT NULL, -- SAR, USD, AED
    currency_name VARCHAR(50) NOT NULL,
    exchange_rate_to_sar DECIMAL(10, 4) DEFAULT 1.0000,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- 2. Brands table
CREATE TABLE brands (
    brand_id SERIAL PRIMARY KEY,
    brand_name VARCHAR(100) NOT NULL,
    country_of_origin VARCHAR(50),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- 3.  Branches table
CREATE TABLE branches (
    branch_id SERIAL PRIMARY KEY,
    branch_name VARCHAR(100) NOT NULL,
    city VARCHAR(50) NOT NULL,
    location_details TEXT,
    manager_name VARCHAR(100),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- 4. Categories table
CREATE TABLE categories (
    category_id SERIAL PRIMARY KEY,
    category_name VARCHAR(100) NOT NULL,
    parent_category_id INT NULL,
    FOREIGN KEY (parent_category_id) REFERENCES categories(category_id)
);

-- 5. Users
CREATE TABLE users (
    user_id SERIAL PRIMARY KEY,
    full_name VARCHAR(150) NOT NULL,
    email VARCHAR(100) UNIQUE NOT NULL,
    phone VARCHAR(20),
    preferred_currency_id INT,
    address TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (preferred_currency_id) REFERENCES currencies(currency_id)
);

-- 6. Products table
CREATE TABLE products (
    product_id SERIAL PRIMARY KEY,
    brand_id INT,
    category_id INT,
    product_name VARCHAR(200) NOT NULL,
    purchase_price DECIMAL(10, 2) NOT NULL,
    sale_price DECIMAL(10, 2) NOT NULL,
    stock_quantity INT DEFAULT 0,
    min_stock_level INT DEFAULT 5,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (brand_id) REFERENCES brands(brand_id),
    FOREIGN KEY (category_id) REFERENCES categories(category_id)
);

-- 7. Payment Methods table
CREATE TABLE payment_methods (
    method_id SERIAL PRIMARY KEY,
    method_name VARCHAR(50) NOT NULL, -- Credit Card, Mada, Apple Pay, Cash
    is_active BOOLEAN DEFAULT TRUE
);

-- 8. orders table
CREATE TABLE orders (
    order_id SERIAL PRIMARY KEY,
    user_id INT,
    branch_id INT,
    currency_id INT,
    order_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    subtotal DECIMAL(10, 2) NOT NULL,
    tax_amount DECIMAL(10, 2) NOT NULL,
    total_amount DECIMAL(10, 2) NOT NULL,
    status VARCHAR(50) DEFAULT 'pending',
    FOREIGN KEY (user_id) REFERENCES users(user_id),
    FOREIGN KEY (branch_id) REFERENCES branches(branch_id),
    FOREIGN KEY (currency_id) REFERENCES currencies(currency_id)
);

-- 9. payments table
CREATE TABLE payments (
    payment_id SERIAL PRIMARY KEY,
    order_id INT,
    method_id INT,
    payment_date TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    amount_paid DECIMAL(10, 2) NOT NULL,
    transaction_reference VARCHAR(100),
    FOREIGN KEY (order_id) REFERENCES orders(order_id),
    FOREIGN KEY (method_id) REFERENCES payment_methods(method_id)
);

-- 10. order_items table
CREATE TABLE order_items (
    order_item_id SERIAL PRIMARY KEY,
    order_id INT,
    product_id INT,
    quantity INT NOT NULL,
    unit_sale_price DECIMAL(10, 2) NOT NULL,
    unit_purchase_price DECIMAL(10, 2) NOT NULL, -- لتثبيت الربح وقت البيع
    FOREIGN KEY (order_id) REFERENCES orders(order_id),
    FOREIGN KEY (product_id) REFERENCES products(product_id)
);

-- Views for reporting
CREATE VIEW sales_profit_report AS
SELECT 
    o.order_id,
    o.order_date,
    SUM(oi.quantity * oi.unit_sale_price) as total_sales,
    SUM(oi.quantity * oi.unit_purchase_price) as total_cost,
    SUM(oi.quantity * (oi.unit_sale_price - oi.unit_purchase_price)) as net_profit
FROM orders o
JOIN order_items oi ON o.order_id = oi.order_id
WHERE o.status != 'cancelled'
GROUP BY o.order_id;
